import{_ as i,o as a,c as s,ag as r,j as t}from"./chunks/framework.WmBmIPw-.js";const x=JSON.parse('{"title":"插入启发式（Insertion Heuristics）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/heuristics/simple/insertion-heuristics.md","filePath":"or-opt/heuristics/simple/insertion-heuristics.md","lastUpdated":1777191149000}'),n={name:"or-opt/heuristics/simple/insertion-heuristics.md"};function o(l,e,h,c,f,d){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="插入启发式-insertion-heuristics" tabindex="-1">插入启发式（Insertion Heuristics） <a class="header-anchor" href="#插入启发式-insertion-heuristics" aria-label="Permalink to &quot;插入启发式（Insertion Heuristics）&quot;">​</a></h1><p>插入启发式是面向 TSP、VRP 等路径问题的经典构造式算法族：不采用「从某点像链条一样只向前延伸」的最近邻式生长，而往往先取一个很小的闭子回路（子环）作为核，再反复把尚未进环的客户「塞进」环上某条弧，直到所有点都进入路径（VRP 时还可同步派车/容量/时间窗检查）。是 <a href="./simple-heuristics.html">基础启发式</a> 中构造式代表之一；与 <a href="./clarke-wright-savings.html">Clarke–Wright 节约</a>、<a href="./greedy-algorithm.html">贪心（构造式）</a> 并列。总览见 <a href="./../heuristic-algorithms.html">启发式算法总览</a>。</p><p><strong>含义</strong>：在最小化总路程时，在弧 (i, j) 上插入 k 的单步附加代价，常写为在一条边上「断开再接」的增值。</p><hr><h2 id="一、核心步骤-三阶段" tabindex="-1">一、核心步骤（三阶段） <a class="header-anchor" href="#一、核心步骤-三阶段" aria-label="Permalink to &quot;一、核心步骤（三阶段）&quot;">​</a></h2><p>整体可概括为：先有环、再定下一个插谁、再定插到哪条弧的哪个位置。下面以单条 TSP 环、最小化总距叙述；CVRP 在「多车/车场/容量」上多一层路由分配，但插入增量与可行性检查仍同型。</p><h3 id="_1-1-选择初始子回路" tabindex="-1">1.1 选择初始子回路 <a class="header-anchor" href="#_1-1-选择初始子回路" aria-label="Permalink to &quot;1.1 选择初始子回路&quot;">​</a></h3><p>先构造一个小的可行闭路（子环或带车场的短环），作为后续插入的载体。常见做法包括：</p><ul><li>取距离最远的两点 i、j 形成往返式小回路（i → j → i，若对称则视作二点环的骨架）。</li><li>取不共线三点作三角形 A–B–C–A，作为初始三角子环。</li><li>有固定车场 0 时，可从 0 出发的短环或经文献约定的种子客户组合出发。</li></ul><p><strong>注</strong>：子环的具体取法在实现中必须固定，否则可复现性受影响。</p><h3 id="_1-2-选择步-下一个插谁" tabindex="-1">1.2 选择步：下一个插谁 <a class="header-anchor" href="#_1-2-选择步-下一个插谁" aria-label="Permalink to &quot;1.2 选择步：下一个插谁&quot;">​</a></h3><p>在尚未出现在当前环上的点中，用某种规则选下一个待插入点 k（与「最近/最远/最省/随机」等选择策略配合，见第三节四种变体）。</p><h3 id="_1-3-插入步-插到哪条弧、增值多少" tabindex="-1">1.3 插入步：插到哪条弧、增值多少 <a class="header-anchor" href="#_1-3-插入步-插到哪条弧、增值多少" aria-label="Permalink to &quot;1.3 插入步：插到哪条弧、增值多少&quot;">​</a></h3><p>对当前环上每一条有向或无序边 (i, j)（在实现里常按邻接顺序扫弧），将 k 插在 i 与 j 之间，即将原弧 (i, j) 换为 (i, k) 与 (k, j)。在仅计路程、且度量由距离 d(·,·) 给定时，该步路程增量为</p><p>[ \\Delta c(i,j,k) = d(i,k) + d(k,j) - d(i,j). ]</p><p>（与文献中 (\\Delta c = d_{ik} + d_{kj} - d_{ij}) 同义。）再在所有可行弧位置上取使 (\\Delta c) 最小者（或结合选择策略的别的准则）。若有容量、时间窗等，还应在 (\\Delta c) 上叠加不可行罚项或直接筛掉不可行弧。</p><p><strong>止</strong>：当所有客户都进环（及 VRP 中车线合法）时停；或不存在可行插入时按实现报错或启用车线扩展。</p><hr><h2 id="二、插入前后示意-在弧上-塞进-k" tabindex="-1">二、插入前后示意（在弧上“塞进”k） <a class="header-anchor" href="#二、插入前后示意-在弧上-塞进-k" aria-label="Permalink to &quot;二、插入前后示意（在弧上“塞进”k）&quot;">​</a></h2>',19),t("figure",null,[t("svg",{xmlns:"http://www.w3.org/2000/svg",viewBox:"0 0 900 230",width:"100%","max-width":"900","aria-label":"在边 i j 上插入 k 的抽象，以及三角子环 A B C 上在 AB 间插入 k"},[t("text",{x:"8",y:"20","font-size":"13",fill:"#333"},"左：在弧 (i, j) 上插入 k"),t("text",{x:"458",y:"20","font-size":"13",fill:"#333"},"右：三角子环 A–B–C 上在 A 与 B 间插入 k"),t("defs",null,[t("marker",{id:"mIns",viewBox:"0 0 10 10",refX:"8",refY:"5",markerWidth:"6",markerHeight:"6",orient:"auto"},[t("path",{d:"M0,0 L10,5 L0,10 z",fill:"#1976d2"})])]),t("text",{x:"8",y:"40","font-size":"11",fill:"#555"},"上：原弧 (i)–(j)。下：拆为 (i)–(k)–(j)；Δc = d(i,k)+d(k,j)−d(i,j)。"),t("g",{transform:"translate(0, 50)"},[t("circle",{cx:"100",cy:"80",r:"8",fill:"#5c5c5c"}),t("text",{x:"92",y:"85","font-size":"12",fill:"#fff","font-weight":"600"},"i"),t("circle",{cx:"300",cy:"80",r:"8",fill:"#5c5c5c"}),t("text",{x:"292",y:"85","font-size":"12",fill:"#fff","font-weight":"600"},"j"),t("line",{x1:"108",y1:"80",x2:"292",y2:"80",stroke:"#1976d2","stroke-width":"2.5","marker-end":"url(#mIns)"})]),t("g",{transform:"translate(0, 50)"},[t("circle",{cx:"100",cy:"140",r:"8",fill:"#5c5c5c"}),t("text",{x:"92",y:"145","font-size":"12",fill:"#fff","font-weight":"600"},"i"),t("circle",{cx:"200",cy:"140",r:"8",fill:"#2e7d32"}),t("text",{x:"194",y:"145","font-size":"11",fill:"#fff","font-weight":"600"},"k"),t("circle",{cx:"300",cy:"140",r:"8",fill:"#5c5c5c"}),t("text",{x:"292",y:"145","font-size":"12",fill:"#fff","font-weight":"600"},"j"),t("line",{x1:"108",y1:"140",x2:"192",y2:"140",stroke:"#2e7d32","stroke-width":"2","marker-end":"url(#mIns)"}),t("line",{x1:"208",y1:"140",x2:"292",y2:"140",stroke:"#2e7d32","stroke-width":"2","marker-end":"url(#mIns)"})]),t("line",{x1:"450",y1:"0",x2:"450",y2:"230",stroke:"#e0e0e0"}),t("g",{transform:"translate(460, 38)"},[t("polygon",{points:"100,20 200,20 150,100",fill:"none",stroke:"#1976d2","stroke-width":"2"}),t("text",{x:"92",y:"18","font-size":"12",fill:"#1976d2","font-weight":"600"},"A"),t("text",{x:"200",y:"18","font-size":"12",fill:"#1976d2","font-weight":"600"},"B"),t("text",{x:"140",y:"110","font-size":"12",fill:"#1976d2","font-weight":"600"},"C"),t("line",{x1:"100",y1:"20",x2:"200",y2:"20",stroke:"#b71c1c","stroke-width":"2"}),t("text",{x:"120",y:"12","font-size":"10",fill:"#b71c1c"},"边 AB 可拆成 A–k–B"),t("circle",{cx:"150",cy:"50",r:"7",fill:"#2e7d32"}),t("text",{x:"145",y:"55","font-size":"10",fill:"#fff","font-weight":"600"},"k"),t("line",{x1:"100",y1:"20",x2:"143",y2:"50",stroke:"#2e7d32","stroke-width":"1.5","stroke-dasharray":"3 2"}),t("line",{x1:"157",y1:"50",x2:"200",y2:"20",stroke:"#2e7d32","stroke-width":"1.5","stroke-dasharray":"3 2"})]),t("g",{transform:"translate(460, 160)"},[t("text",{x:"0",y:"0","font-size":"11",fill:"#555"},"环上实作应对每条可插弧 (i, j) 试算 Δc 并配合第三节的选择规则。")])]),t("figcaption",{style:{"font-size":"0.9em",color:"#555","margin-top":"0.25em"}},"左：在一条弧上把 k 插入的抽象（上下两行表示插入前后）。右：三角子环在 AB 上「开口」接 k；闭合路径中还需保持与其余边的衔接。")],-1),r('<hr><h2 id="三、四种常见变体" tabindex="-1">三、四种常见变体 <a class="header-anchor" href="#三、四种常见变体" aria-label="Permalink to &quot;三、四种常见变体&quot;">​</a></h2><p>「下一步选谁进环」与「在全体弧上选哪里最省」可以组合。下面四个是教材与实现里常见的「选择下一待插点」策略；插入位仍按上一节的 (\\Delta c) 在弧上求（或作后悔值等扩展；与 Regret 等的关系见 D 后一段的说明）。</p><h3 id="a-最近插入-nearest-insertion" tabindex="-1">A. 最近插入（Nearest Insertion） <a class="header-anchor" href="#a-最近插入-nearest-insertion" aria-label="Permalink to &quot;A. 最近插入（Nearest Insertion）&quot;">​</a></h3><p><strong>逻辑</strong>：在尚未进环的客户中，选与当前路线上任一点距离最近的那个作为下一步的 k。<br><strong>特点</strong>：优先把已离路很近的客户先接进环，路线在局部上常较紧凑。因始终在环上更新，与链式最近邻相比，更顾路径闭合。见 <a href="./greedy-algorithm.html">贪心（构造式）</a> 中最近邻与链式生长的对照。</p><h3 id="b-最远插入-farthest-insertion" tabindex="-1">B. 最远插入（Farthest Insertion） <a class="header-anchor" href="#b-最远插入-farthest-insertion" aria-label="Permalink to &quot;B. 最远插入（Farthest Insertion）&quot;">​</a></h3><p><strong>逻辑</strong>：在尚未进环的客户中，使 k 到「当前路线上各点的最短距离」取最大的那个，即最靠外的未进环点。<br><strong>直觉</strong>：先搭出外轮廓，减轻末期被迫拉长线去接远处点。多本教材与经验认为，在以上四种简单选择规则中，最远插入往往最稳健、效果常较好；仍依实例与实现为准。<br><strong>示意</strong>：可想象一团已进环点与环外更远的 k，最远插入会优先接环外缘；最近插入更倾向贴住已有团簇。纸上画点即可对比。</p><h3 id="c-最省插入-最廉插入-cheapest-insertion" tabindex="-1">C. 最省插入 / 最廉插入（Cheapest Insertion） <a class="header-anchor" href="#c-最省插入-最廉插入-cheapest-insertion" aria-label="Permalink to &quot;C. 最省插入 / 最廉插入（Cheapest Insertion）&quot;">​</a></h3><p><strong>逻辑</strong>：枚举所有未进环的 k 与当前环上所有可插弧 (i, j)，在全体 (k, i, j) 组合上取 (\\Delta c(i,j,k)) 全局长最小的那一步。<br><strong>特点</strong>：单步在谁与哪条弧上极度贪心，只在乎当步边际代价最小。实现上可比重，但单步计算量可较大。</p><h3 id="d-随机插入-random-insertion" tabindex="-1">D. 随机插入（Random Insertion） <a class="header-anchor" href="#d-随机插入-random-insertion" aria-label="Permalink to &quot;D. 随机插入（Random Insertion）&quot;">​</a></h3><p><strong>逻辑</strong>：从尚未进环的客户中随机选 k，再在弧的选取上依实现（可随机、可再取最小 (\\Delta c) 等）。<br><strong>用途</strong>：在 <a href="./../meta/grasp.html">GRASP</a>、<a href="./../meta/alns.html">ALNS</a> 等元启发式中增加多解、多样性，避免总是同一条构造序列。</p><p><strong>注</strong>：另有一种 Regret 插入（次优与最优插入位置代价差大者优先），与 ALNS 修复常见，见 <a href="./../meta/alns.html">ALNS</a>。「随机化最廉」指在一步内对多个低 (\\Delta c) 位再随机，与 D 的「人随机」可组合，编码时建议分开写清。第三节标题「四种」为教材常见分法，Regret 作扩展单列。</p><hr><h2 id="四、与-cvrp、alns-的关系" tabindex="-1">四、与 CVRP、ALNS 的关系 <a class="header-anchor" href="#四、与-cvrp、alns-的关系" aria-label="Permalink to &quot;四、与 CVRP、ALNS 的关系&quot;">​</a></h2><ul><li>CVRP 在「下一点插进哪条车、是否新开」上比 TSP 多一层，但弧上插一点的 (\\Delta c) 与容量、时间窗检查仍同型。</li><li><a href="./../meta/alns.html">ALNS</a> 的修复算子是大邻域上反复插拔，不是本页从子环一次建满的纯构造，但插入增量同一套公式。</li><li><a href="./clarke-wright-savings.html">Clarke–Wright 节约</a> 是边合并，不是向弧中塞点；可先 C-W 出粗解，再用插入抛光或作修复链。</li></ul><p><strong>注</strong>：子环与弧的存法、有向/无向、起点是否固定、并列最小 (\\Delta c) 时的决胜规则，应写在可复现说明中。</p>',16)])])}const g=i(n,[["render",o]]);export{x as __pageData,g as default};
